INSERT INTO `policy_providers` (`id`, `code`, `company_name`, `contact_person_name`, `contact_person_email`, `contact_person_phone`, `is_api`, `api_url`, `api_key`, `api_secret`, `status`, `logo`, `template_img`, `created_at`, `updated_at`, `claim_info`, `user_id`) VALUES
(2, '01', 'Green Delta', 'Name 1', 'info@dnsgroup.net', '00000000000', 0, NULL, NULL, NULL, 0, '2025-03-10-67ce81833c2b2.jpg', '2022-07-31-62e65068448f9.png', '2022-07-31 09:50:32', '2025-03-10 06:06:59', '<div class=\"swal2-content\"><div id=\"swal2-content\" style=\"display: block;\"><div><h6 style=\"color: #3aade1;\">WHAT TO DO IN THE CASE OF A MEDICAL EMERGENCY</h6> \r\n                <p style=\"line-height: 18px;\">In the event of Illness or Accident abroad which may lead to Hospital treatment or Curtailment of your trip</p>\r\n                <h5 style=\"text-decoration:underline; font-size: 12px; color: #555;\">Please Contact</h5>\r\n                <h2 style=\"text-decoration:underline;     font-size: 18px;    color: #555;\">INTANA GLOBAL</h2>\r\n                <p style=\"line-height: 18px;\">Sussex House, Perrymount Road, Haywards Heath, West Sussex RH 16 1 DN\r\n                <b>Telephone:</b> +44(0) 207 902 7405\r\n                <b>Email:</b> ops@intana-global.com</p>\r\n                <blockquote style=\"    font-size: 10px;    line-height: 15px;    padding: 10px !important;    margin: 0;\">\r\n                    NB : (1) To avoid reverse charge calls, the claimant and/or someone calling on his/her behalf over above telephone/fax be requested to give his/her telephone number so that the INTANA GLOBAL can immediately call back asking for other particulars. (2) INTANA GLOBAL is acting as Third Party Administrators/Assistance provider to render services in respect of claims to the Overseas Mediclaim Policy holders. In the event of a claim, please apply to INTANA GLOBAL for a Claim Form. When completed, please submit direct to INTANA GLOBAL together with the Insurance Certificate and relevant documentation.\r\n                    </blockquote></div>\r\n                </div><input class=\"swal2-input\" style=\"display: none;\"><input type=\"file\" class=\"swal2-file\" style=\"display: none;\"><div class=\"swal2-range\" style=\"display: none;\"><input type=\"range\"><output></output></div><select class=\"swal2-select\" style=\"display: none;\"></select><div class=\"swal2-radio\" style=\"display: none;\"></div><label for=\"swal2-checkbox\" class=\"swal2-checkbox\" style=\"display: none;\"><input type=\"checkbox\"></label><textarea class=\"swal2-textarea\" style=\"display: none;\"></textarea><div class=\"swal2-validationerror\" id=\"swal2-validationerror\" style=\"display: none;\"></div></div>', NULL),
(3, '02', 'Instasure', 'Rafel Kabir', 'info@instasure.xyz', '09606252525', 0, NULL, NULL, NULL, 0, '2022-09-01-63106cc7a5cfc.png', 'default.png', '2022-09-01 08:26:47', '2022-09-01 08:26:47', NULL, NULL),
(4, '03', 'Eastern Insurance Co. Ltd.', 'Test', 'mohammad.ali@dnsgroup.net', '01712655156', 0, NULL, NULL, NULL, 0, '2025-03-10-67ce81d76a60d.jpg', 'default.png', '2022-09-06 10:38:18', '2025-03-10 06:08:23', NULL, NULL),
