INSERT INTO `sliders` (`id`, `title`, `content`, `image`, `created_at`, `updated_at`) VALUES
(1, 'Mobile Insurance', 'เฆเฆชเฆจเฆพเฆฐ เฆธเฆฎเฆธเงเฆฏเฆพเง เฆเฆเฆเฆฟ เฆซเงเฆจ เฆเฆฒ เฆเฆจเงเฆคเง เฆชเฆพเฆฐเง เฆธเฆฎเฆพเฆงเฆพเฆจเฅค เฆเฆฟเฆจเงเฆคเง เฆเฆชเฆจเฆพเฆฐ เฆซเงเฆจ เฆจเฆฟเฆเงเฆ เฆฏเฆฆเฆฟ เฆธเฆฎเฆธเงเฆฏเฆพเฆฐ เฆเฆพเฆฐเฆฃ เฆนเง, เฆคเฆพเฆเฆฒเง เฆคเฆพเฆฐ เฆธเฆฎเฆพเฆงเฆพเฆจ เฆเฆฟ?', 'uploads/sliders/sMGzw7k3bYaFcqPBKsqPXzWB23Capi20Mx8AGvnV.jpg', '2021-05-02 19:05:53', '2022-07-19 06:20:25'),
